package com.eagle.app.controller;

import com.eagle.app.dto.*;
import com.eagle.app.model.*;
import com.eagle.app.repository.*;
import com.eagle.app.service.ReservationService;
import org.springframework.data.domain.*;
import org.springframework.web.bind.annotation.*;
import java.security.Principal;
import java.util.List;

@RestController
@RequestMapping("/api/v1/reservations")
public class ReservationController {
    private final ReservationRepository reservations;
    private final ReservationService service;
    private final UserRepository users;
    private final RoomRepository rooms;

    public ReservationController(ReservationRepository reservations, ReservationService service, UserRepository users, RoomRepository rooms) {
        this.reservations = reservations;
        this.service = service;
        this.users = users;
        this.rooms = rooms;
    }

    @GetMapping
    public Page<ReservationResponse> list(Pageable pageable) {
        return reservations.findAll(pageable).map(ReservationResponse::from);
    }

    @GetMapping("/mine")
    public Page<ReservationResponse> mine(Pageable pageable, Principal principal) {
        String username = principal == null ? "requester.demo" : principal.getName();
        List<ReservationResponse> all = reservations.findByRequester_UsernameOrderByStartTimeDesc(username).stream().map(ReservationResponse::from).toList();
        int start = (int) pageable.getOffset();
        int end = Math.min(start + pageable.getPageSize(), all.size());
        return new PageImpl<>(start >= all.size() ? List.of() : all.subList(start, end), pageable, all.size());
    }

    @PostMapping
    public ReservationResponse create(@RequestBody ReservationRequest req, Principal principal) {
        Reservation r = new Reservation();
        if (req.requesterId() != null) {
            r.requester = users.findById(req.requesterId()).orElseThrow(() -> new IllegalArgumentException("Requester not found"));
        } else {
            String username = principal == null ? "requester.demo" : principal.getName();
            r.requester = users.findByUsername(username).orElseThrow(() -> new IllegalArgumentException("Requester not found"));
        }
        r.room = rooms.findById(req.roomId()).orElseThrow(() -> new IllegalArgumentException("Room not found"));
        r.startTime = req.startTime();
        r.endTime = req.endTime();
        r.status = req.status() == null ? ReservationStatus.PENDING : req.status();
        return ReservationResponse.from(service.createReservation(r));
    }
}

