    private final BannerTemplateRepository templates;
    private final ShiftHandoffRepository handoffs;
    private final UserRepository users;
    private final FrontDeskReservationService reservationService;
    private final NotificationService notifications;

    public FrontDeskController(ReservationRepository reservations, BannerTemplateRepository templates,
                               ShiftHandoffRepository handoffs, UserRepository users,
                               FrontDeskReservationService reservationService, NotificationService notifications) {
        this.reservations = reservations;
        this.templates = templates;
        this.handoffs = handoffs;
        this.users = users;
        this.reservationService = reservationService;
