+        h.toUser = users.findById(req.toUserId()).orElseThrow(() -> new IllegalArgumentException("to user not found"));
+        h.handoffTime = req.handoffTime();
+        h.summary = req.summary();
+        h.pendingTasks = req.pendingTasks();
