+    return this.http.get<PageResponse<Reservation>>("/api/v1/reservations/mine?page=0&size=20");
+  }
+
+  scheduleBoard(): Observable<PageResponse<Reservation>> {
+    return this.http.get<PageResponse<Reservation>>("/api/v1/frontdesk/schedule-board?page=0&size=20");
+  }
+
+  createReservation(roomId: number, startTime: string, endTime: string): Observable<unknown> {
